/**
 * SMS notification adapter.
 *
 * Implements NotificationAdapter for the 'sms' channel.
 * Formats notifications as short text messages and delivers
 * via a pluggable SmsTransport. Uses an in-memory transport
 * by default; inject a custom SmsTransport for production
 * use (Twilio, AWS SNS, etc.).
 *
 * NOTE: User preferences were designed assuming email-only channels.
 * The PreferencesService.shouldNotify() currently has no SMS-specific
 * logic — it falls through to "allow by default" for non-email channels.
 * This needs to be updated to support per-channel SMS preferences.
 * See COORDINATION.md for details.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationResult,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface SmsConfig {
  /** Sender phone number or short code (e.g., "+15551234567") */
  fromNumber: string;
  /** Maximum retries on transient failure */
  maxRetries?: number;
}

/**
 * A rendered SMS message ready for delivery.
 */
export interface RenderedSms {
  from: string;
  to: string;
  body: string;
}

/**
 * Transport interface for sending SMS messages.
 * Swap this out for production providers (Twilio, AWS SNS, etc.).
 */
export interface SmsTransport {
  send(sms: RenderedSms): Promise<{ success: boolean; error?: string }>;
  isConnected(): Promise<boolean>;
}

/**
 * Default in-memory transport — stores sent SMS messages for testing/dev.
 */
export class InMemorySmsTransport implements SmsTransport {
  private sent: RenderedSms[] = [];

  async send(sms: RenderedSms): Promise<{ success: boolean; error?: string }> {
    this.sent.push(sms);
    return { success: true };
  }

  async isConnected(): Promise<boolean> {
    return true;
  }

  getSentMessages(): RenderedSms[] {
    return [...this.sent];
  }

  clearSentMessages(): void {
    this.sent = [];
  }
}

/**
 * SMS message templates keyed by notification type.
 * SMS messages are short — subject + condensed body, under 160 chars when possible.
 */
const SMS_TEMPLATES: Record<NotificationType, (payload: NotificationPayload) => string> = {
  'order-confirmation': (payload) =>
    `Order Confirmed: ${payload.subject}. ${payload.body}`,
  'order-status-update': (payload) =>
    `${payload.subject}: ${payload.body}`,
  'user-welcome': (payload) =>
    `${payload.subject} ${payload.body}`,
  'user-updated': (payload) =>
    `Account Updated: ${payload.body}`,
  'system-alert': (payload) =>
    `[ALERT] ${payload.subject}: ${payload.body}`,
};

/**
 * Resolve the recipient phone number from a NotificationPayload.
 * Validates that the recipient is non-empty. Logs a warning if
 * the value doesn't look like a phone number (starts with '+').
 */
function resolveRecipient(recipient: string, logger: Logger): string {
  const trimmed = recipient.trim();
  if (!trimmed) {
    throw new Error('Recipient is empty');
  }
  if (!trimmed.startsWith('+')) {
    logger.warn(
      `Recipient "${trimmed}" does not look like a phone number — delivering as-is`,
    );
  }
  return trimmed;
}

export class SmsAdapter implements NotificationAdapter {
  readonly channel = 'sms' as const;
  private logger = new Logger('SmsAdapter');
  private transport: SmsTransport;
  private sent: NotificationPayload[] = [];
  private maxRetries: number;

  constructor(
    private config: SmsConfig,
    transport?: SmsTransport,
  ) {
    this.transport = transport ?? new InMemorySmsTransport();
    this.maxRetries = config.maxRetries ?? 2;
  }

  /**
   * Render the payload into an SMS message and deliver through the transport.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(
      `Sending SMS to ${payload.recipient}: "${payload.subject}"`,
    );

    try {
      const to = resolveRecipient(payload.recipient, this.logger);
      const body = this.renderTemplate(payload);

      const sms: RenderedSms = {
        from: this.config.fromNumber,
        to,
        body,
      };

      const transportResult = await this.sendWithRetry(sms);

      if (!transportResult.success) {
        return {
          notificationId: payload.id,
          channel: 'sms',
          success: false,
          error: transportResult.error ?? 'SMS delivery failed',
          deliveredAt: new Date(),
        };
      }

      // Track for testing / audit
      this.sent.push(payload);

      return {
        notificationId: payload.id,
        channel: 'sms',
        success: true,
        deliveredAt: new Date(),
      };
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      this.logger.error(`SMS send failed: ${message}`);
      return {
        notificationId: payload.id,
        channel: 'sms',
        success: false,
        error: message,
        deliveredAt: new Date(),
      };
    }
  }

  /**
   * Check if the SMS transport is available.
   */
  async isAvailable(): Promise<boolean> {
    try {
      return await this.transport.isConnected();
    } catch {
      return false;
    }
  }

  /**
   * Render an SMS body using the template for the notification type.
   */
  renderTemplate(payload: NotificationPayload): string {
    const renderer = SMS_TEMPLATES[payload.type];
    return renderer(payload);
  }

  /**
   * Get all successfully sent payloads. Useful for testing.
   */
  getSentMessages(): NotificationPayload[] {
    return [...this.sent];
  }

  /**
   * Clear sent messages. Useful for testing.
   */
  clearSentMessages(): void {
    this.sent = [];
  }

  /**
   * Get the underlying transport (useful for testing with InMemorySmsTransport).
   */
  getTransport(): SmsTransport {
    return this.transport;
  }

  /**
   * Attempt to send with retries on transient failure.
   */
  private async sendWithRetry(
    sms: RenderedSms,
  ): Promise<{ success: boolean; error?: string }> {
    let lastError: string | undefined;

    for (let attempt = 0; attempt <= this.maxRetries; attempt++) {
      const result = await this.transport.send(sms);
      if (result.success) {
        return result;
      }
      lastError = result.error;
      this.logger.warn(
        `SMS delivery attempt ${attempt + 1} failed: ${lastError}`,
      );
    }

    return { success: false, error: lastError };
  }
}

