import { describe, it, expect, beforeEach } from 'vitest';
import {
  SmsAdapter,
  InMemorySmsTransport,
} from '../../src/adapters/sms.adapter.js';
import type {
  SmsTransport,
  RenderedSms,
} from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order-confirmation',
    channel: 'sms',
    recipient: '+15551234567',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    priority: 'normal',
    metadata: {},
    createdAt: new Date('2026-01-15T12:00:00Z'),
    ...overrides,
  };
}

describe('SmsAdapter', () => {
  let adapter: SmsAdapter;
  let transport: InMemorySmsTransport;

  beforeEach(() => {
    transport = new InMemorySmsTransport();
    adapter = new SmsAdapter({ fromNumber: '+15559999999' }, transport);
  });

  describe('channel', () => {
    it('should report channel as sms', () => {
      expect(adapter.channel).toBe('sms');
    });
  });

  describe('isAvailable', () => {
    it('should return true when transport is connected', async () => {
      expect(await adapter.isAvailable()).toBe(true);
    });

    it('should return false when transport throws', async () => {
      const failTransport: SmsTransport = {
        send: async () => ({ success: true }),
        isConnected: async () => { throw new Error('network error'); },
      };
      const failAdapter = new SmsAdapter({ fromNumber: '+1' }, failTransport);
      expect(await failAdapter.isAvailable()).toBe(false);
    });
  });

  describe('send', () => {
    it('should send successfully and track the payload', async () => {
      const payload = makePayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.notificationId).toBe('notif-0001');
      expect(result.channel).toBe('sms');
      expect(result.deliveredAt).toBeInstanceOf(Date);

      expect(adapter.getSentMessages()).toHaveLength(1);
      expect(adapter.getSentMessages()[0]?.id).toBe('notif-0001');
    });

    it('should deliver correct rendered SMS to transport', async () => {
      const payload = makePayload();
      await adapter.send(payload);

      const sent = transport.getSentMessages();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.from).toBe('+15559999999');
      expect(sent[0]?.to).toBe('+15551234567');
      expect(sent[0]?.body).toContain('Order Confirmed');
      expect(sent[0]?.body).toContain('Widget x2');
    });

    it('should return failure when transport fails', async () => {
      const failTransport: SmsTransport = {
        send: async () => ({ success: false, error: 'Carrier rejected' }),
        isConnected: async () => true,
      };
      const failAdapter = new SmsAdapter({ fromNumber: '+1', maxRetries: 0 }, failTransport);

      const result = await failAdapter.send(makePayload());
      expect(result.success).toBe(false);
      expect(result.error).toBe('Carrier rejected');
    });

    it('should return failure when recipient is empty', async () => {
      const payload = makePayload({ recipient: '   ' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Recipient is empty');
    });

    it('should accept non-phone-number recipients with a warning', async () => {
      const payload = makePayload({ recipient: 'user-123' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      const sent = transport.getSentMessages();
      expect(sent[0]?.to).toBe('user-123');
    });
  });

  describe('retry logic', () => {
    it('should retry on failure up to maxRetries', async () => {
      let attempts = 0;
      const flakyTransport: SmsTransport = {
        send: async () => {
          attempts++;
          if (attempts < 3) {
            return { success: false, error: 'Temporary failure' };
          }
          return { success: true };
        },
        isConnected: async () => true,
      };

      const retryAdapter = new SmsAdapter({ fromNumber: '+1', maxRetries: 2 }, flakyTransport);
      const result = await retryAdapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(attempts).toBe(3); // 1 initial + 2 retries
    });

    it('should give up after maxRetries exhausted', async () => {
      const failTransport: SmsTransport = {
        send: async () => ({ success: false, error: 'always fails' }),
        isConnected: async () => true,
      };

      const retryAdapter = new SmsAdapter({ fromNumber: '+1', maxRetries: 1 }, failTransport);
      const result = await retryAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('always fails');
    });
  });

  describe('template rendering', () => {
    it('should render all notification types', async () => {
      const types = [
        'order-confirmation',
        'order-status-update',
        'user-welcome',
        'user-updated',
        'system-alert',
      ] as const;

      for (const type of types) {
        transport.clearSentMessages();
        const payload = makePayload({ type, id: `notif-${type}` });
        const result = await adapter.send(payload);

        expect(result.success).toBe(true);
        const sent = transport.getSentMessages();
        expect(sent).toHaveLength(1);
        expect(sent[0]?.body.length).toBeGreaterThan(0);
      }
    });

    it('should render order-confirmation with Order Confirmed prefix', () => {
      const body = adapter.renderTemplate(makePayload({ type: 'order-confirmation' }));
      expect(body).toMatch(/^Order Confirmed:/);
    });

    it('should render system-alert with [ALERT] prefix', () => {
      const body = adapter.renderTemplate(makePayload({ type: 'system-alert' }));
      expect(body).toMatch(/^\[ALERT\]/);
    });
  });

  describe('getSentMessages / clearSentMessages', () => {
    it('should return a copy of sent messages', async () => {
      await adapter.send(makePayload());
      const sent = adapter.getSentMessages();
      sent.pop(); // mutate the copy
      expect(adapter.getSentMessages()).toHaveLength(1);
    });

    it('should clear sent messages', async () => {
      await adapter.send(makePayload());
      adapter.clearSentMessages();
      expect(adapter.getSentMessages()).toHaveLength(0);
    });
  });

  describe('InMemorySmsTransport', () => {
    it('should store and return sent messages', async () => {
      const sms: RenderedSms = {
        from: '+15559999999',
        to: '+15551234567',
        body: 'Test message',
      };

      const result = await transport.send(sms);
      expect(result.success).toBe(true);
      expect(transport.getSentMessages()).toHaveLength(1);
      expect(transport.getSentMessages()[0]?.to).toBe('+15551234567');
    });

    it('should clear stored messages', async () => {
      const sms: RenderedSms = { from: '+1', to: '+2', body: 'x' };
      await transport.send(sms);
      transport.clearSentMessages();
      expect(transport.getSentMessages()).toHaveLength(0);
    });

    it('should report connected', async () => {
      expect(await transport.isConnected()).toBe(true);
    });
  });
});

